import{_ as e,c as o,o as a,V as n}from"./chunks/framework.1sOznGPE.js";const u=JSON.parse('{"title":"npm介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/node/npm/npm介绍.md","filePath":"guide/node/npm/npm介绍.md","lastUpdated":1718632692000}'),t={name:"guide/node/npm/npm介绍.md"},d=n('<h1 id="npm介绍" tabindex="-1">npm介绍 <a class="header-anchor" href="#npm介绍" aria-label="Permalink to &quot;npm介绍&quot;">​</a></h1><p><code>npm</code>（全称 Node Package Manager）是 Node.js 的包管理工具，它是一个基于命令行的工具，用于帮助开发者在自己的项目中安装、升级、移除和管理依赖项。</p><ul><li>类似于 <code>PHP</code> 的工具：<code>Composer</code>。它是 PHP 的包管理器，可以用于下载、安装和管理 PHP 的依赖项，类似于 npm。</li><li>类似于 <code>Java</code> 的工具：<code>Maven</code>。它是 Java 的构建工具和项目管理工具，可以自动化构建、测试和部署 Java 应用程序，类似于 npm 和 webpack 的功能。</li><li>类似于 <code>Python</code> 的工具：<code>pip</code>。它是 Python 的包管理器，可以用于安装和管理 Python 的依赖项，类似于 npm。</li><li>类似于 <code>Rust</code> 的工具：<code>Cargo</code>。它是 Rust 的包管理器和构建工具，可以用于下载、编译和管理 Rust 的依赖项，类似于 npm 和 Maven 的功能。</li></ul><p><a href="https://docs.npmjs.com/" target="_blank" rel="noreferrer">https://docs.npmjs.com/</a></p>',4),c=[d];function p(s,r,m,_,i,l){return a(),o("div",null,c)}const P=e(t,[["render",p]]);export{u as __pageData,P as default};
